import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String input = scanner.nextLine();

        // Limit the input size to prevent buffer overflow
        int maxLength = 10;
        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Copy input to buffer with proper length
        char[] buffer = new char[maxLength];
        input.getChars(0, Math.min(input.length(), maxLength), buffer, 0);

        System.out.println("Buffer: " + new String(buffer));
    }
}

